// ========== Custom Timber Trees ==========

class ProductionTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (priority >= Log.VERBOSE) {
            val logEntry = LogEntry(
                timestamp = System.currentTimeMillis(),
                priority = priority,
                tag = tag ?: "UNTAGGED",
                message = message,
                throwable = t
            )
            LogBuffer.addEntry(logEntry)
        }
    }
}

class FileLoggingTree(private val application: Application) : Timber.Tree() {
    
    private val executor = Executors.newSingleThreadExecutor()
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val fileDateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)
    
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        executor.execute {
            try {
                val logDir = File(application.filesDir, "logs")
                if (!logDir.exists()) logDir.mkdirs()
                
                val fileName = "app_log_${fileDateFormat.format(Date())}.txt"
                val logFile = File(logDir, fileName)
                
                val priorityChar = when (priority) {
                    Log.VERBOSE -> "V"
                    Log.DEBUG -> "D"
                    Log.INFO -> "I"
                    Log.WARN -> "W"
                    Log.ERROR -> "E"
                    Log.ASSERT -> "A"
                    else -> "?"
                }
                
                val timestamp = dateFormat.format(Date())
                val logMessage = buildString {
                    append("$timestamp $priorityChar/$tag: $message")
                    if (t != null) {
                        append("\n")
                        append(getFullStackTrace(t))
                    }
                    append("\n")
                }
                
                FileWriter(logFile, true).use { writer ->
                    writer.append(logMessage)
                }
                
                // Rotate logs - keep only last 7 days
                cleanOldLogs(logDir, 7)
                
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Failed to write log to file", e)
            }
        }
    }
    
    private fun getFullStackTrace(throwable: Throwable): String {
        val sw = StringWriter()
        val pw = PrintWriter(sw)
        throwable.printStackTrace(pw)
        return sw.toString()
    }
    
    private fun cleanOldLogs(logDir: File, keepDays: Int) {
        val cutoff = System.currentTimeMillis() - (keepDays * 24 * 60 * 60 * 1000L)
        logDir.listFiles()?.forEach { file ->
            if (file.lastModified() < cutoff) {
                file.delete()
            }
        }
    }
}

// ========== Log Entry & Buffer ==========

data class LogEntry(
    val timestamp: Long,
    val priority: Int,
    val tag: String,
    val message: String,
    val throwable: Throwable? = null
) {
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    
    override fun toString(): String {
        val priorityStr = when (priority) {
            Log.VERBOSE -> "VERBOSE"
            Log.DEBUG -> "DEBUG"
            Log.INFO -> "INFO"
            Log.WARN -> "WARN"
            Log.ERROR -> "ERROR"
            Log.ASSERT -> "ASSERT"
            else -> "UNKNOWN"
        }
        return "[${dateFormat.format(Date(timestamp))}] $priorityStr/$tag: $message"
    }
}

object LogBuffer {
    private const val MAX_BUFFER_SIZE = 5000
    private val buffer = ConcurrentLinkedQueue<LogEntry>()
    
    fun addEntry(entry: LogEntry) {
        buffer.add(entry)
        while (buffer.size > MAX_BUFFER_SIZE) {
            buffer.poll()
        }
    }
    
    fun getEntries(): List<LogEntry> = buffer.toList()
    
    fun getEntriesByTag(tag: String): List<LogEntry> = buffer.filter { it.tag == tag }
    
    fun getEntriesByPriority(minPriority: Int): List<LogEntry> = buffer.filter { it.priority >= minPriority }
    
    fun clear() = buffer.clear()
    
    fun exportAsString(): String = buffer.joinToString("\n") { it.toString() }
}

// ========== Main App Logger ==========

object AppLogger {
    
    private lateinit var application: Application
    private val sessionId = UUID.randomUUID().toString().substring(0, 8)
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    
    fun initialize(app: Application) {
        application = app
        Timber.v("=== Logging Session Started: $sessionId ===")
        Timber.v("Device: ${android.os.Build.MANUFACTURER} ${android.os.Build.MODEL}")
        Timber.v("Android Version: ${android.os.Build.VERSION.RELEASE} (API ${android.os.Build.VERSION.SDK_INT})")
        
        // Set up global uncaught exception handler
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            logUncaughtException(thread, throwable)
            defaultHandler?.uncaughtException(thread, throwable)
        }
    }
    
    private fun logUncaughtException(thread: Thread, throwable: Throwable) {
        Timber.e(throwable, "UNCAUGHT EXCEPTION on thread '${thread.name}' (id=${thread.id})")
        ExceptionLogger.logException("UncaughtException", throwable, mapOf(
            "thread_name" to thread.name,
            "thread_id" to thread.id.toString(),
            "session_id" to sessionId
        ))
    }
    
    fun getSessionId(): String = sessionId
}

