            append("  Timestamp   : ${getCurrentTimestamp()}\n")
            append("═══════════════════════════════════════")
        })
    }
    
    fun logRegistrationSuccess(username: String, userId: String) {
        Timber.tag(TAG).i("✅ Registration successful - Username: $username, UserID: $userId")
    }
    
    fun logRegistrationFailure(username: String, reason: String, exception: Throwable? = null) {
        Timber.tag(TAG).w(exception, "❌ Registration failed - Username: $username, Reason: $reason")
    }
    
    fun logPasswordResetRequest(email: String) {
        Timber.tag(TAG).v("Password reset requested for: ${maskEmail(email)}")
    }
    
    fun logBiometricAuth(success: Boolean, errorMessage: String? = null) {
        if (success) {
            Timber.tag(TAG).i("✅ Biometric authentication successful")
        } else {
            Timber.tag(TAG).w("❌ Biometric authentication failed: $errorMessage")
        }
    }
    
    private fun maskEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***"
        val name = parts[0]
        val masked = if (name.length > 2) {
            "${name.first()}${"*".repeat(name.length - 2)}${name.last()}"
        } else {
            "*".repeat(name.length)
        }
        return "$masked@${parts[1]}"
    }
}

// ========== Database Query Logger ==========

object DatabaseLogger {
    private const val TAG = "DATABASE"
    
    fun logQuery(
        query: String,
        parameters: Map<String, Any?> = emptyMap(),
        tableName: String? = null,
        operationType: String = "SELECT"
    ) {
        val startTime = System.nanoTime()
        Timber.tag(TAG).v(buildString {
            append("───────────────────────────────────────\n")
            append("  DB QUERY START\n")
            append("───────────────────────────────────────\n")
            append("  Operation  : $operationType\n")
            if (tableName != null) append("  Table      : $tableName\n")
            append("  Query      : $query\n")
            if (parameters.isNotEmpty()) {
                append("  Parameters :\n")
                parameters.forEach { (key, value) ->
                    append("    $key = ${formatParam(value)}\n")
                }
            }
            append("  Timestamp  : ${getCurrentTimestamp()}\n")
            append("  Thread     : ${Thread.currentThread().name}\n")
            append("───────────────────────────────────────")
        })
    }
    
    fun logQueryResult(
        query: String,
        resultCount: Int,
        executionTimeMs: Long,
        tableName: String? = null,
        parameters: Map<String, Any?> = emptyMap()
    ) {
        val logLevel = when {
            executionTimeMs > 1000 -> Log.WARN
            executionTimeMs > 500 -> Log.INFO
            else -> Log.VERBOSE
        }
        
        val message = buildString {
            append("───────────────────────────────────────\n")
            append("  DB QUERY RESULT\n")
            append("───────────────────────────────────────\n")
            if (tableName != null) append("  Table        : $tableName\n")
            append("  Query        : $query\n")
            if (parameters.isNotEmpty()) {
                append("  Parameters   :\n")
                parameters.forEach { (key, value) ->
                    append("    $key = ${formatParam(value)}\n")
                }
            }
            append("  Result Count : $resultCount\n")
            append("  Exec Time    : ${executionTimeMs}ms")
            if (executionTimeMs > 500) append(" ⚠️ SLOW QUERY")
            if (executionTimeMs > 1000) append(" 🔴 VERY SLOW")
            append("\n")
            append("  Timestamp    : ${getCurrentTimestamp()}\n")
            append("───────────────────────────────────────")
        }
        
        when (logLevel) {
            Log.WARN -> Timber.tag(TAG).w(message)
            Log.INFO -> Timber.tag(TAG).i(message)
            else -> Timber.tag(TAG).v(message)
        }
    }
    
    fun logQueryError(
        query: String,
        exception: Throwable,
        parameters: Map<String, Any?> = emptyMap(),
        tableName: String? = null
    ) {
        Timber.tag(TAG).e(exception, buildString {
            append("═══════════════════════════════════════\n")
            append("  ❌ DB QUERY ERROR\n")
            append("═══════════════════════════════════════\n")
            if (tableName != null) append("  Table      : $tableName\n")
            append("  Query      : $query\n")
            if (parameters.isNotEmpty()) {
                append("  Parameters :\n")
                parameters.forEach { (key, value) ->
                    append("    $key = ${formatParam(value)}\n")
                }
            }
            append("  Error      : ${exception.javaClass.simpleName}: ${exception.message}\n")
            append("  Stack Trace:\n")
            append(getFullStackTrace(exception).prependIndent("    "))
            append("  Timestamp  : ${getCurrentTimestamp()}\n")
            append("═══════════════════════════════════════")
        })
    }
    
    fun logTransaction(action: String, success: Boolean, durationMs: Long? = null, error: Throwable? = null) {
        if (success) {
            Timber.tag(TAG).v(buildString {
                append("✅ Transaction $action completed")
                if (durationMs != null) append(" in ${durationMs}ms")
            })
        } else {
            Timber.tag(TAG).e(error, "❌ Transaction $action FAILED: ${error?.message}")
        }
    }
    
    fun logMigration(fromVersion: Int, toVersion: Int, success: Boolean, durationMs: Long? = null) {
        if (success) {
            Timber.tag(TAG).i("✅ DB Migration $fromVersion -> $toVersion completed in ${durationMs ?: "?"}ms")
        } else {
            Timber.tag(TAG).e("❌ DB Migration $fromVersion -> $toVersion FAILED")
        }
    }
    
    fun logInsert(tableName: String, data: Map<String, Any?>, rowId: Long? = null) {
        Timber.tag(TAG).v(buildString {
            append("INSERT into $tableName")
            if (rowId != null) append(" -> rowId=$rowId")
            append("\n  Data: ")
            data.forEach { (key, value) ->
                append("\n    $key = ${formatParam(value)}")
            }
        })
    }
    
    fun logUpdate(tableName: String, whereClause: String, affectedRows: Int, data: Map<String, Any?> = emptyMap()) {
        Timber.tag(TAG).v(buildString {
            append("UPDATE $tableName WHERE $whereClause -> $affectedRows rows affected")
            if (data.isNotEmpty()) {
                append("\n  Updated Data:")
                data.forEach { (key, value) ->
                    append("\n    $key = ${formatParam(value)}")
                }
            }
        })
    }
    
    fun logDelete(tableName: String, whereClause: String, affectedRows: Int) {
        Timber.tag(TAG).v("DELETE from $tableName WHERE $whereClause -> $affectedRows rows affected")
    }
    
    private fun formatParam(value: Any?): String {
        return when (value) {
            null -> "NULL"
            is String -> "\"$value\" (String, len=${value.length})"
            is ByteArray -> "[ByteArray, size=${value.size}]"
            is Collection<*> -> "[Collection, size=${value.size}]"
            else -> "$value (${value.javaClass.simpleName})"
        }
    }
}

// ========== API Request Logger ==========

object ApiLogger {
    private const val TAG = "API"
    
    fun logRequest(
        method: String,
        url: String,
        headers: Map<String, String> = emptyMap(),
        body: String? = null,
        queryParams: Map<String, String> = emptyMap(),
        requestId: String = UUID.randomUUID().toString().substring(0, 8)
    ): String {
        Timber.tag(TAG).v(buildString {
            append("═══════════════════════════════════════\n")
            append("  ➡️ API REQUEST [$requestId]\n")
            append("═══════════════════════════════════════\n")
            append("  Method     : $method\n")
            append("  URL        : $url\n")
            append("  Timestamp  : ${getCurrentTimestamp()}\n")
            append("  Thread     : ${Thread.currentThread().name}\n")
            
            if (queryParams.isNotEmpty()) {
                append("  Query Params:\n")
                queryParams.forEach { (key, value) ->
                    append("    $key = $value\n")
                }
            }
            
            if (headers.isNotEmpty()) {
                append("  Headers    :\n")
                headers.forEach { (key, value) ->
                    val displayValue = if (key.equals("Authorization", ignoreCase = true)) {
                        maskAuthHeader(value)
                    } else {
                        value
                    }
                    append("    $key: $displayValue\n")
                }
            }
            
            if (body != null) {
                append("  Body       :\n")
                append("    ${formatBody(body)}\n")
                append("  Body Size  : ${body.length} bytes\n")
            }
            
            append("═══════════════════════════════════════")
        })
        return requestId
    }
    
    fun logResponse(
        requestId: String,
        method: String,
        url: String,
        statusCode: Int,
        statusMessage: String? = null,
        headers: Map<String, String> = emptyMap(),
        body: String? = null,
        durationMs: Long,
        bytesSent: Long? = null,
        bytesReceived: Long? = null
    ) {
        val statusEmoji = when {
            statusCode in 200..299 -> "✅"
            statusCode in 300..399 -> "↪️"
            statusCode in 400..499 -> "⚠️"
            statusCode >= 500 -> "🔴"
            else -> "❓"
        }
        
        val logLevel = when {
            statusCode >= 500 -> Log.ERROR
            statusCode >= 400 -> Log.WARN
            durationMs > 5000 -> Log.WARN
            else -> Log.VERBOSE
        }
        
        val message = buildString {
            append("═══════════════════════════════════════\n")
            append("  $statusEmoji API RESPONSE [$requestId]\n")
            append("═══════════════════════════════════════\n")
            append("  Method       : $method\n")
            append("  URL          : $url\n")
            append("  Status       : $statusCode")
            if (statusMessage != null) append(" ($statusMessage)")
            append("\n")
            append("  Duration     : ${durationMs}ms")
            if (durationMs > 3000) append(" ⚠️ SLOW")
            if (durationMs > 10000) append(" 🔴 VERY SLOW")
            append("\n")
            
            if (bytesSent != null) append("  Bytes Sent   : $bytesSent\n")
            if (bytesReceived != null) append("  Bytes Recv   : $bytesReceived\n")
            
            append("  Timestamp    : ${getCurrentTimestamp()}\n")
            
            if (headers.isNotEmpty()) {
                append("  Response Headers:\n")
                headers.forEach { (key, value) ->
                    append("    $key: $value\n")
                }
            }
            
            if (body != null) {
                val truncatedBody = if (body.length > 2000) {
                    "${body.substring(0, 2000)}... [TRUNCATED, total: ${body.length} chars]"
                } else {
                    body
                }
                append("  Response Body:\n")
                append("    ${formatBody(truncatedBody)}\n")
            }
            
            append("═══════════════════════════════════════")
        }
        
        when (logLevel) {
            Log.ERROR -> Timber.tag(TAG).e(message)
            Log.WARN -> Timber.tag(TAG).w(message)
            else -> Timber.tag(TAG).v(message)
        }
    }
    
    fun logRequestError(
        requestId: String,
        method: String,
        url: String,
        exception: Throwable,
        durationMs: Long? = null
    ) {
        Timber.tag(TAG).e(exception, buildString {
            append("═══════════════════════════════════════\n")
            append("  🔴 API REQUEST ERROR [$requestId]\n")
            append("═══════════════════════════════════════\n")
            append("  Method     : $method\n")
            append("  URL        : $url\n")
            if (durationMs != null) append("  Duration   : ${durationMs}ms\n")
            append("  Error Type : ${exception.javaClass.simpleName}\n")
            append("  Message    : ${exception.message}\n")
            append("  Timestamp  : ${getCurrentTimestamp()}\n")
            append("  Stack Trace:\n")
            append(getFullStackTrace(exception).prependIndent("    "))
            append("═══════════════════════════════════════")
        })
    }
    
    fun logRetry(requestId: String, attemptNumber: Int, maxAttempts: Int, delayMs: Long) {
        Timber.tag(TAG).w(
            "🔄 Retry [$requestId] - Attempt $attemptNumber/$maxAttempts, delay: ${delayMs}ms"
        )
    }
    
    fun logTimeout(requestId: String, url: String, timeoutMs: Long) {
        Timber.tag(TAG).w("⏱️ Request timeout [$requestId] - URL: $url, Timeout: ${timeoutMs}ms")
    }
    
    fun logCacheHit(url: String, cacheAge: Long?) {
        Timber.tag(TAG).v("📦 Cache hit for: $url (age: ${cacheAge ?: "?"}ms)")
    }
    
    fun logCacheMiss(url: String) {
        Timber.tag(TAG).v("📦 Cache miss for: $url")
    }
    
    private fun maskAuthHeader(value: String): String {
        return when {
            value.startsWith("Bearer ", ignoreCase = true) -> {
                val token = value.substring(7)
                if (token.length > 10) {
                    "Bearer ${token.substring(0, 5)}...${token.substring(token.length - 5)}"
                } else {
                    "Bearer ***"
                }
            }
            value.startsWith("Basic ", ignoreCase = true) -> "Basic ***"
            else -> {
                if (value.length > 10) {
                    "${value.substring(0, 5)}...${value.substring(value.length - 3)}"
                } else {
                    "***"
                }
            }
        }
    }
    
    private fun formatBody(body: String): String {
        return try {
            // Try to pretty-print JSON
            if (body.trimStart().startsWith("{") || body.trimStart().startsWith("[")) {
                val json = org.json.JSONObject(body)
                json.toString(2)
            } else {
                body
            }
        } catch (e: Exception) {
            body
        }
    }
}

// ========== Exception Logger ==========

object ExceptionLogger {
    private const val TAG = "EXCEPTION"
    
    fun logException(
        context: String,
        exception: Throwable,
        additionalData: Map<String, String> = emptyMap()
    ) {
        Timber.tag(TAG).e(exception, buildString {
            append("╔═══════════════════════════════════════\n")
            append("║  🔴 EXCEPTION CAUGHT\n")
            append("╠═══════════════════════════════════════\n")
            append("║  Context     : $context\n")
            append("║  Type        : ${exception.javaClass.canonicalName}\n")
            append("║  Message     : ${exception.message}\n")
            append("║  Timestamp   : ${getCurrentTimestamp()}\n")
            append("║  Thread      : ${Thread.currentThread().name}\n")
            append("║  Session     : ${AppLogger.getSessionId()}\n")
            
            if (additionalData.isNotEmpty()) {
                append("║  Additional Data:\n")
                additionalData.forEach { (key, value) ->
                    append("║    $key: $value\n")
                }
            }
            
            // Log the full causal chain
            var cause = exception.cause
            var depth = 1
            while (cause != null) {
                append("║\n")
                append("║  Cause #$depth  : ${cause.javaClass.canonicalName}\n")
                append("║  Message    : ${cause.message}\n")
                cause = cause.cause
                depth++
            }
            
            append("║\n")
            append("║  Full Stack Trace:\n")
            append(getFullStackTrace(exception).lines().joinToString("\n") { "║    $it" })
            append("\n")
            append("╚═══════════════════════════════════════")
        })
    }
    
    fun logWarning(context: String, message: String, exception: Throwable? = null) {
        Timber.tag(TAG).w(exception, buildString {
            append("⚠️ WARNING in $context: $message")
            if (exception != null) {
                append("\n  Exception: ${exception.javaClass.simpleName}: ${exception.message}")
            }
        })
    }
    
    fun logNonFatal(context: String, exception: Throwable) {
        Timber.tag(TAG).w(exception, buildString {
            append("⚠️ NON-FATAL: $context\n")
            append("  Type    : ${exception.javaClass.simpleName}\n")
            append("  Message : ${exception.message}\n")
            append("  Thread  : ${Thread.currentThread().name}")
        })
    }
}

// ========== Performance Logger ==========

object PerformanceLogger {
    private const val TAG = "PERFORMANCE"
    private val timers = mutableMapOf<String, Long>()
    
    fun startTimer(label: String) {
        timers[label] = System.nanoTime()
        Timber.tag(TAG).v("⏱️ Timer started: $label")
    }
    
    fun stopTimer(label: String): Long {
        val startTime = timers.remove(label)
        if (startTime == null) {
            Timber.tag(TAG).w("⏱️ Timer not found: $label")
            return -1
        }
        val durationMs = (System.nanoTime() - startTime) / 1_000_000
        
        val logLevel = when {
            durationMs > 5000 -> Log.ERROR
            durationMs > 2000 -> Log.WARN
            durationMs > 500 -> Log.INFO
            else -> Log.VERBOSE
        }
        
        val message = buildString {
            append("⏱️ Timer '$label': ${durationMs}ms")
            if (durationMs > 2000) append(" ⚠️ SLOW")
            if (durationMs > 5000) append(" 🔴 CRITICAL")
        }
        
        when (logLevel) {
            Log.ERROR -> Timber.tag(TAG).e(message)
            Log.WARN -> Timber.tag(TAG).w(message)
            Log.INFO -> Timber.tag(TAG).i(message)
            else -> Timber.tag(TAG).v(message)
        }
        
        return durationMs
    }
    
    fun logMemoryUsage(context: String = "") {
        val runtime = Runtime.getRuntime()
        val totalMemory = runtime.totalMemory() / (1024 * 1024)
        val freeMemory = runtime.freeMemory() / (1024 * 1024)
        val usedMemory = totalMemory - freeMemory
        val maxMemory = runtime.maxMemory() / (1024 * 1024)
        
        Timber.tag(TAG).v(buildString {
            append("📊 Memory Usage")
            if (context.isNotEmpty()) append(" ($context)")
            append(":\n")
            append("  Used: ${usedMemory}MB / Total: ${totalMemory}MB / Max: ${maxMemory}MB\n")
            append("  Free: ${freeMemory}MB (${(freeMemory * 100 / totalMemory)}%)")
        })
    }
    
    fun logFrameRate(fps: Float) {
        val message = "🖥️ Frame Rate: ${String.format("%.1f", fps)} FPS"
        if (fps < 30) {
            Timber.tag(TAG).w("$message ⚠️ LOW FPS")
        } else {
            Timber.tag(TAG).v(message)
        }
    }
}

