// ========== Log Export Utility ==========

object LogExporter {
    private const val TAG = "LOG_EXPORT"
    
    fun exportLogsToFile(application: Application): File? {
        return try {
            val logDir = File(application.filesDir, "logs")
            val exportFile = File(application.cacheDir, "exported_logs_${System.currentTimeMillis()}.txt")
            
            val writer = FileWriter(exportFile)
            
            writer.append("=== App Log Export ===\n")
            writer.append("Session: ${AppLogger.getSessionId()}\n")
            writer.append("Export Time: ${getCurrentTimestamp()}\n")
            writer.append("Device: ${android.os.Build.MANUFACTURER} ${android.os.Build.MODEL}\n")
            writer.append("Android: ${android.os.Build.VERSION.RELEASE} (API ${android.os.Build.VERSION.SDK_INT})\n")
            writer.append("===========================\n\n")
            
            // Append buffered logs
            writer.append("=== Buffered Logs ===\n")
            writer.append(LogBuffer.exportAsString())
            writer.append("\n\n")
            
            // Append file logs
            if (logDir.exists()) {
                logDir.listFiles()?.sortedBy { it.name }?.forEach { file ->
                    writer.append("=== File: ${file.name} ===\n")
                    writer.append(file.readText())
                    writer.append("\n")
                }
            }
            
            writer.close()
            
            Timber.tag(TAG).i("Logs exported to: ${exportFile.absolutePath}")
            exportFile
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "Failed to export logs")
            null
        }
    }
    
    fun getLogsSummary(): String {
        val entries = LogBuffer.getEntries()
        val errorCount = entries.count { it.priority >= Log.ERROR }
        val warnCount = entries.count { it.priority == Log.WARN }
        val totalCount = entries.size
        
        return buildString {
            append("Log Summary:\n")
            append("  Total entries: $totalCount\n")
            append("  Errors: $errorCount\n")
            append("  Warnings: $warnCount\n")
            append("  Session: ${AppLogger.getSessionId()}\n")
        }
    }
}

// ========== Utility Functions ==========

private fun getCurrentTimestamp(): String {
    return SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US).format(Date())
}

private fun getFullStackTrace(throwable: Throwable): String {
    val sw = StringWriter()
    val pw = PrintWriter(sw)
    throwable.printStackTrace(pw)
    return sw.toString()
}

private fun formatBody(body: String): String {
    return try {
        if (body.trimStart().startsWith("{") || body.trimStart().startsWith("[")) {
            org.json.JSONObject(body).toString(2)
        } else {
            body
        }
    } catch (e: Exception) {
        body
    }
}

// ========== Inline Performance Measurement ==========

inline fun <T> measureAndLog(label: String, block: () -> T): T {
    PerformanceLogger.startTimer(label)
    return try {
        val result = block()
        PerformanceLogger.stopTimer(label)
        result
    } catch (e: Exception) {
        PerformanceLogger.stopTimer(label)
        ExceptionLogger.logException("measureAndLog($label)", e)
        throw e
    }
}

// ========== OkHttp Interceptor for API Logging ==========

/*
 * Usage with OkHttp:
 *
 * val client = OkHttpClient.Builder()
 *     .addInterceptor(LoggingInterceptor())
 *     .build()
 */

class LoggingInterceptor : okhttp3.Interceptor {
    override fun intercept(chain: okhttp3.Interceptor.Chain): okhttp3.Response {
        val request = chain.request()
        val startTime = System.currentTimeMillis()
        
        // Log request
        val requestHeaders = mutableMapOf<String, String>()
        request.headers.forEach { (name, value) ->
            requestHeaders[name] = value
        }
        
        val requestBody = try {
            val buffer = okio.Buffer()
            request.body?.writeTo(buffer)
            buffer.readUtf8()
        } catch (e: Exception) {
            null
        }
        
        val requestId = ApiLogger.logRequest(
            method = request.method,
            url = request.url.toString(),
            headers = requestHeaders,
            body = requestBody,
            queryParams = request.url.queryParameterNames.associateWith { 
                request.url.queryParameter(it) ?: "" 
            }
        )
        
        return try {
            val response = chain.proceed(request)
            val duration = System.currentTimeMillis() - startTime
            
            val responseHeaders = mutableMapOf<String, String>()
            response.headers.forEach { (name, value) ->
                responseHeaders[name] = value
            }
            
            // Read response body without consuming it
            val responseBody = response.peekBody(Long.MAX_VALUE).string()
            
            ApiLogger.logResponse(
                requestId = requestId,
                method = request.method,
                url = request.url.toString(),
                statusCode = response.code,
                statusMessage = response.message,
                headers = responseHeaders,
                body = responseBody,
                durationMs = duration,
                bytesReceived = responseBody.length.toLong()
            )
            
            response
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            ApiLogger.logRequestError(
                requestId = requestId,
                method = request.method,
                url = request.url.toString(),
                exception = e,
                durationMs = duration
            )
            throw e
        }
    }
}

// ========== Database Query Timer Helper ==========

class QueryTimer(
    private val query: String,
    private val tableName: String? = null,
    private val parameters: Map<String, Any?> = emptyMap()
) {
    private val startTime = System.currentTimeMillis()
    
    init {
        DatabaseLogger.logQuery(
            query = query,
            parameters = parameters,
            tableName = tableName
        )
    }
    
    fun logSuccess(resultCount: Int) {
        val duration = System.currentTimeMillis() - startTime
        DatabaseLogger.logQueryResult(
            query = query,
            resultCount = resultCount,
            executionTimeMs = duration,
            tableName = tableName,
            parameters = parameters
        )
    }
    
    fun logError(exception: Throwable) {
        DatabaseLogger.logQueryError(
            query = query,
            exception = exception,
            parameters = parameters,
            tableName = tableName
        )
    }
}